// HasTask applies the HasEdge predicate on the "task" edge.
func HasTask() predicate.WorkflowTaskEvent {
	return predicate.WorkflowTaskEvent(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, TaskTable, TaskColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTaskWith applies the HasEdge predicate on the "task" edge with a given conditions (other predicates).
func HasTaskWith(preds ...predicate.WorkflowTask) predicate.WorkflowTaskEvent {
	return predicate.WorkflowTaskEvent(func(s *sql.Selector) {
		step := newTaskStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.WorkflowTaskEvent) predicate.WorkflowTaskEvent {
	return predicate.WorkflowTaskEvent(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.WorkflowTaskEvent) predicate.WorkflowTaskEvent {
	return predicate.WorkflowTaskEvent(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.WorkflowTaskEvent) predicate.WorkflowTaskEvent {
	return predicate.WorkflowTaskEvent(sql.NotPredicates(p))
}
